#include <stdio.h>

// We declare this returns an 'int'
int addNumbers(int a, int b) {
    int sum = a + b;
    return sum; // Hand the answer back
}

int main() {
    // The function call is REPLACED by the returned answer
    int result = addNumbers(10, 5);

    printf("The result is %d", result);
    return 0;
}
